export async function GET(context) {
  const blog = (await getCollection("blog")).filter((post) => !post.data.draft);

  const projects = (await getCollection("projects")).filter(
    (project) => !project.data.draft,
  );

  const items = [...blog, ...projects].sort(
    (a, b) => new Date(b.data.date).valueOf() - new Date(a.data.date).valueOf(),
  );

  return rss({
    title: SITE.TITLE,
    description: SITE.DESCRIPTION,
    site: context.site,
    items: items.map((item) => ({
      title: item.data.title,
      description: item.data.description,
      pubDate: item.data.date,
      link: `/${item.collection}/${item.slug}/`,
    })),
  });
}

import type { CollectionEntry } from "astro:content";

type GroupKey = string | number | symbol;
type GroupFunction<T> = (item: T, index?: number) => GroupKey;

export function getPostsByGroupCondition(
  posts: CollectionEntry<"posts">[],
  groupFunction: GroupFunction<CollectionEntry<"posts">>
) {
  const result: Record<GroupKey, CollectionEntry<"posts">[]> = {};

  for (let i = 0; i < posts.length; i++) {
    const item = posts[i];
    const groupKey = groupFunction(item, i);

    if (!result[groupKey]) {
      result[groupKey] = [];
    }

    result[groupKey].push(item);
  }

  return result;
}

export function groupCollectionsByYear<T extends CollectionKey>(
  collections: Collections
): [number, CollectionEntry<T>[]][] {
  const collectionsByYear = collections.reduce((acc, collection) => {
    const year = getYearFromCollection(collection)
    if (year !== undefined) {
      if (!acc.has(year)) {
        acc.set(year, [])
      }
      acc.get(year)?.push(collection)
    }
    return acc
  }, new Map<number, Collections>())

  return Array.from(
    collectionsByYear.entries() as IterableIterator<[number, CollectionEntry<T>[]]>
  ).sort((a, b) => b[0] - a[0])
}

import { I18N } from 'astrowind:config';

export const formatter: Intl.DateTimeFormat = new Intl.DateTimeFormat(I18N?.language, {
  year: 'numeric',
  month: 'short',
  day: 'numeric',
  timeZone: 'UTC',
});

export const getFormattedDate = (date: Date): string => (date ? formatter.format(date) : '');

export const trim = (str = '', ch?: string) => {
  let start = 0,
    end = str.length || 0;
  while (start < end && str[start] === ch) ++start;
  while (end > start && str[end - 1] === ch) --end;
  return start > 0 || end < str.length ? str.substring(start, end) : str;
};

function buildOpenGraph(og: MetaDataOpenGraph): SEOProps['openGraph'] | undefined {
  if (!og) return undefined;

  const imageUrl = firstImage?.url || '';
  if (!imageUrl) return undefined;

  return {
    basic: {
      title: title || METADATA?.title?.default || '',
      type: og.type || 'website',
      image: imageUrl,
      url: og.url,
    },
    optional: {
      description: description || METADATA?.description,
      locale: og.locale,
      siteName: og.siteName,
    },
    image: {
      url: imageUrl,
      width: firstImage?.width,
      height: firstImage?.height,
      alt: title || METADATA?.title?.default || '',
    },
  };
}

async function fetchWebmentions(timeFrom: string | null, perPage = 1000) {
	if (!DOMAIN) {
		console.warn("No domain specified. Please set in astro.config.ts");
		return null;
	}

	if (!WEBMENTION_API_KEY) {
		console.warn("No webmention api token specified in .env");
		return null;
	}

	let url = `https://webmention.io/api/mentions.jf2?domain=${hostName}&token=${WEBMENTION_API_KEY}&sort-dir=up&per-page=${perPage}`;

	if (timeFrom) url += `&since${timeFrom}`;

	const res = await fetch(url);

	if (res.ok) {
		const data = (await res.json()) as WebmentionsFeed;
		return data;
	}

	return null;
}

async function detectInstalledCollections(root: URL) {
  try {
    let packages: string[] = [];
    const text = await readFile(new URL("./package.json", root), {
      encoding: "utf8",
    });
    const { dependencies = {}, devDependencies = {} } = JSON.parse(text);
    packages.push(...Object.keys(dependencies));
    packages.push(...Object.keys(devDependencies));
    const collections = packages
      .filter((name) => name.startsWith("@iconify-json/"))
      .map((name) => name.replace("@iconify-json/", ""));
    return collections;
  } catch {}
  return [];
}

func isValidTSXAttribute(a Attribute) bool {
	if a.Type == SpreadAttribute {
		return true
	}

	for i, ch := range a.Key {
		if i == 0 && !isValidFirstRune(ch) {
			return false
		}

		// See https://tc39.es/ecma262/#prod-IdentifierName
		if i != 0 && !(isValidFirstRune(ch) ||
			unicode.In(ch, unicode.Mn, unicode.Mc, unicode.Nd, unicode.Pc)) &&
			// : is allowed inside TSX attributes, for namespaces purpose
			// See https://facebook.github.io/jsx/#prod-JSXNamespacedName
			// - is allowed inside TSX attributes, for custom attributes
			// See https://facebook.github.io/jsx/#prod-JSXIdentifier
			ch != ':' && ch != '-' {
			return false
		}
	}

	return true
}

